#include <stdio.h>

int main() {
    int marks = 75;

    if (marks >= 80) {
        printf("A+\n");
    } else if (marks >= 60) {
        printf("A\n");
    } else {
        printf("আরও চেষ্টা করুন\n");
    }
    return 0;
}

int day = 3;
switch (day) {
    case 1:
        printf("শনিবার\n");
        break;
    case 2:
        printf("রবিবার\n");
        break;
    case 3:
        printf("সোমবার\n");
        break;
    default:
        printf("অজানা দিন\n");
}

int age = 20;
int result = (age >= 18) ? 1 : 0;
printf("প্রাপ্তবয়স্ক: %d\n", result); // 1 মানে true
